import type { RefObject } from 'react';
import type { PANELS } from './constants';
export type Nullable<T> = T | null;
export type Panel = (typeof PANELS)[keyof typeof PANELS];
/** Тип для одиночной даты (ISO-строка) */
export type SingleDateValue = string;
/** Тип для диапазона дат (2 ISO-строки), либо пустых */
export type RangeDateValue = string[];
/** Универсальный тип: может быть одиночная или массив (диапазон/мультивыбор) */
export type DateValue = SingleDateValue | RangeDateValue;
export interface PresetPeriod {
    label: string;
    range: [string, string];
}
export interface CalendarProps {
    /**
     * Дата или массив дат в виде строки,
     * представляющая упрощенный или расширенный формат даты календаря ISO 8601.
     * @example
     * value: '2022-05-20T00:00:00Z'
     * value: '2022-05-20'
     * value: new Date().toISOString()
     *
     * либо массив из дат, если включён режим multiselect/диапазона.
     */
    value: DateValue;
    /**
     * Дата в виде строки,
     * представляющая упрощенный или расширенный формат даты календаря ISO 8601..
     * Минимальная дата, которую может выбрать пользователь
     * Сравнение выполняется по календарному дню на UTC-полуночь, чтобы избежать ошибок из-за часовых поясов
     * @example
     * minValue: '2022-05-20T00:00:00Z'
     */
    minValue?: SingleDateValue;
    /**
     * Дата в виде строки,
     * представляющая упрощенный или расширенный формат даты календаря ISO 8601..
     * Максимальная дата, которую может выбрать пользователь
     * Сравнение выполняется по календарному дню на UTC-полуночь, чтобы избежать ошибок из-за часовых поясов
     * @example
     * maxValue: '2022-05-20T00:00:00Z'
     */
    maxValue?: SingleDateValue;
    /**
     * Отключает возможность выбрать начальную дату
     */
    disabledStartDate?: boolean;
    /**
     * Отключает возможность выбрать конечную дату
     */
    disabledEndDate?: boolean;
    className?: string;
    dataTestId?: string;
    datepickerRef?: RefObject<HTMLDivElement>;
    outputDateFormat?: string;
    /**
     * Включает функционал множественного выбора дат.
     * Для выбора диапазона дат используйте компонент RangeCalendar.
     */
    multiselect?: boolean;
    /**
     * Текст кнопки сохранения дат.
     * Работает только с multiselect.
     */
    saveButtonTitle?: string;
    /**
     * Режим просмотра календаря, отключающий редактирование дат.
     */
    readonly?: boolean;
    /**Включается мобильное представление календаря */
    mobileView?: boolean;
    onSelectDate?: (date: DateValue) => void;
    onOutsideClick?: () => void;
    /**
     * @deprecated используйте пропс {@link CalendarProps.onSaveClick}
     * Обработчик события нажатия кнопки "Сохранить"
     */
    onClickSelectDates?: () => void;
    /**
     * Обработчик события нажатия кнопки "Сохранить"
     *
     * если передан кнопка будет отрисована
     */
    onSaveClick?: () => void;
    /**
     * Коллбек, который определяет должен ли день быть задисейблен
     */
    excludeDate?: (date: Date) => boolean;
    /**
     * Дата которая определяет, какая страница календаря должна показываться
     * @example Thu Feb 29 2024 10:27:58 GMT+0000
     * @deprecated Используйте `initialViewDate` вместо этого.
     */
    customViewDate?: string;
    /**
     * Дата которая определяет, какая страница календаря должна показываться
     * Принимает тот же формат что и value (ISO строка)
     * @example "2024-02-15T10:27:58.000Z" или "2024-02-15"
     */
    initialViewDate?: string;
    /**
     * Коллбек, который определяет должен ли день быть выходным (цифры красного цвета)
     */
    holidaysDate?: (date: Date) => boolean;
    /**
     * Коллбек для кастомизации дня в календаре
     * Может возвращать строку с классами или React элемент для рендера внутри ячейки дня
     */
    customizeDay?: (date: Date) => {
        className?: string;
        content?: React.ReactNode;
    };
    enableTimePicker?: boolean;
    timeRange?: [string, string];
    outOfRangeErrorText?: string;
    /**
     * Часовой пояс (IANA string). Если не задан, используем локальный пояс.
     * Например: 'Europe/Moscow', 'America/New_York', 'Asia/Tokyo',
     */
    timeZone?: string;
    /**
     * Настройки отображения дней соседних месяцев
     */
    showAdjacentMonthDays?: {
        /**
         * Показывать дни предыдущего месяца
         */
        showPrevious?: boolean;
        /**
         * Показывать дни следующего месяца
         */
        showNext?: boolean;
    };
    /**
     * Разрешает выбор дат соседних месяцев (предыдущего и следующего)
     * Работает только при включенном showAdjacentMonthDays
     */
    allowAdjacentMonthSelection?: boolean;
}
export type RangeCalendarProps = Omit<CalendarProps, 'value'> & {
    /**
     * Массив дат в виде строки,
     * представляющая упрощенный или расширенный формат даты календаря ISO 8601.
     * @example
     * value: '2022-05-20T00:00:00Z'
     * value: '2022-05-20'
     * value: new Date().toISOString()
     */
    value: RangeDateValue;
    /**
     * Массив предустановленных периодов для быстрого выбора
     */
    presetPeriods?: PresetPeriod[];
    /**
     * Коллбек выбора предустановленного периода
     */
    onPresetPeriodSelect?: (range: [string, string]) => void;
};
export interface CalendatRangeStatusOfDays {
    starting: boolean;
    ranging: boolean;
    ending: boolean;
}
